body:
If I inspect this image I get:
```
$ skopeo inspect --override-os=windows --config  --insecure-policy \
    docker://mcr.microsoft.com/windows/nanoserver:20H2 

{
    "created": "2021-04-30T07:20:45.4345264Z",
    "architecture": "amd64",
    "os": "windows",
    "config": {
        "User": "ContainerUser",
        "Cmd": [
            "c:\\windows\\system32\\cmd.exe"
        ]
    },
    "rootfs": {
        "type": "layers",
        "diff_ids": [
            "sha256:e4e02f4caaa37d28ad4b66babf9d64098e81f08c0be24ea427614eafcbbdc3de"
        ]
    },
    "history": [
        {
            "created": "2021-04-30T07:20:45.4345264Z",
            "created_by": "Apply image 20H2-amd64"
        }
    ]
}
```
Yet when I copy the image, the config file has a `rootfS` instead of a `rootfs` (all lowercase):
```
$ skopeo copy --override-os=windows   --insecure-policy docker://mcr.microsoft.com/windows/nanoserver:20H2 \
    docker-archive:mcr.microsoft.com-windows-nanoserver-20H2.tar


$ mkdir mcr.microsoft.com-windows-nanoserver-20H2
$ tar -xf mcr.microsoft.com-windows-nanoserver-20H2.tar -C mcr.microsoft.com-windows-nanoserver-20H2
$ jq . "mcr.microsoft.com-windows-nanoserver-20H2/67f0a0c2d8efc23f33d6978e9a2f039e2cbddae683a0b7918b74ace10467935b.json"
{
  "architecture": "amd64",
  "os": "windows",
  "os.version": "10.0.19042.985",
  "created": "2021-04-30T07:20:45.4345264+00:00",
  "history": [
    {
      "created": "2021-04-30T07:20:45.4345264+00:00",
      "created_by": "Apply image 20H2-amd64"
    }
  ],
  "rootfS": {
    "type": "layers",
    "diff_ids": [
      "sha256:e4e02f4caaa37d28ad4b66babf9d64098e81f08c0be24ea427614eafcbbdc3de"
    ]
  },
  "config": {
    "user": "ContainerUser",
    "cmd": [
      "c:\\windows\\system32\\cmd.exe"
    ]
  }
}
```
